var platforms = [];
var editingId = null;
var activeState = true;
function formatDate(d) {
  if (!d) return '—';
  return new Date(d).toLocaleDateString('en-GB', {
    day: '2-digit',
    month: 'short',
    year: 'numeric'
  });
}
function updateToggleUI() {
  var btn = document.getElementById('f_active_toggle');
  var lbl = document.getElementById('f_active_label');
  if (!btn) return;
  btn.className = 'toggle ' + (activeState ? 'on' : 'off');
  lbl.textContent = activeState ? 'Active' : 'Inactive';
}
function render(model) {
  platforms = model.platforms || [];
  var tbody = document.getElementById('table_body');
  if (!tbody) return;
  if (!platforms.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="empty">No platforms yet</td></tr>';
    return;
  }
  tbody.innerHTML = platforms.map(function (p, i) {
    var activeBadge = p.active ? '<span class="active-badge active-yes">Active</span>' : '<span class="active-badge active-no">Inactive</span>';
    return '<tr>' + '<td><strong>' + (p.platform || '—') + '</strong></td>' + '<td><span class="fee-pct">' + (p.fee_percentage !== null ? p.fee_percentage + '%' : '—') + '</span></td>' + '<td>' + formatDate(p.effective_from) + '</td>' + '<td>' + activeBadge + '</td>' + '<td style="display:flex;gap:6px">' + '<button class="btn-sm btn-edit" onclick="window.editPlatform(' + i + ')">Edit</button>' + '<button class="btn-sm btn-delete" onclick="window.deletePlatform(' + i + ')">Delete</button>' + '</td>' + '</tr>';
  }).join('');
}
window.openForm = function () {
  editingId = null;
  activeState = true;
  document.getElementById('form_title').textContent = 'Add Platform';
  document.getElementById('f_platform').value = '';
  document.getElementById('f_fee').value = '';
  updateToggleUI();
  document.getElementById('form_panel').classList.add('open');
};
window.closeForm = function () {
  document.getElementById('form_panel').classList.remove('open');
};
window.toggleActive = function () {
  activeState = !activeState;
  updateToggleUI();
};
window.editPlatform = function (i) {
  var p = platforms[i];
  if (!p) return;
  editingId = p.platform_fee_id;
  activeState = p.active;
  document.getElementById('form_title').textContent = 'Edit Platform';
  document.getElementById('f_platform').value = p.platform || '';
  document.getElementById('f_fee').value = p.fee_percentage !== null ? p.fee_percentage : '';
  updateToggleUI();
  document.getElementById('form_panel').classList.add('open');
};
window.deletePlatform = function (i) {
  var p = platforms[i];
  if (!p) return;
  appsmith.updateModel({
    delete_id: p.platform_fee_id
  });
  appsmith.triggerEvent('onDeletePlatform');
};
window.savePlatform = function () {
  var name = document.getElementById('f_platform').value.trim();
  var fee = document.getElementById('f_fee').value;
  if (!name) {
    alert('Platform name is required');
    return;
  }
  appsmith.updateModel({
    platform_fee_id: editingId,
    platform: name,
    fee_percentage: fee !== '' ? parseFloat(fee) : 0,
    active: activeState,
    is_edit: editingId !== null
  });
  appsmith.triggerEvent('onSavePlatform');
  window.closeForm();
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function () {
  render(appsmith.model);
});

